import React, { useEffect, useRef, useState } from "react"
import Button from "@material-ui/core/Button"
import IconButton from "@material-ui/core/IconButton"
import TextField from "@material-ui/core/TextField"
import AssignmentIcon from "@material-ui/icons/Assignment"
import PhoneIcon from "@material-ui/icons/Phone"
import { CopyToClipboard } from "react-copy-to-clipboard"
import Peer from "simple-peer"
import io from "socket.io-client"
import { Box, Container, Grid, Paper, Typography } from "@material-ui/core"


const socket = io.connect('http://localhost:5000')

function VideoStream() {

	const [me, setMe] = useState("")
	const [stream, setStream] = useState(null)
	const [receivingCall, setReceivingCall] = useState(false)
	const [caller, setCaller] = useState("")
	const [callerSignal, setCallerSignal] = useState()
	const [callAccepted, setCallAccepted] = useState(false)
	const [idToCall, setIdToCall] = useState("")
	const [callEnded, setCallEnded] = useState(false)
	const [name, setName] = useState("")
	const myVideo = useRef()
	const userVideo = useRef()
	const connectionRef = useRef()

	useEffect(() => {
		navigator.mediaDevices.getUserMedia({ video: true, audio: true })
		.then((stream) => {
			setStream(stream);
			myVideo.current.srcObject = stream;

		})

		socket.on("me", (id) => {
			setMe(id)
		})

		socket.on("callUser", (data) => {
			setReceivingCall(true)
			setCaller(data.from)
			setName(data.name)
			setCallerSignal(data.signal)
		})


	}, [])

	const callUser = (id) => {
		const peer = new Peer({
			initiator: true,
			trickle: false,
			stream: stream
		})
		peer.on("signal", (data) => {
			socket.emit("callUser", {
				userToCall: id,
				signalData: data,
				from: me,
				name: name
			})
		})
		peer.on("stream", (stream) => {

			userVideo.current.srcObject = stream

		})
		socket.on("callAccepted", (signal) => {
			setCallAccepted(true)
			peer.signal(signal)
		})

		connectionRef.current = peer
	}

	const answerCall = () => {
		setCallAccepted(true)
		const peer = new Peer({
			initiator: false,
			trickle: false,
			stream: stream
		})
		peer.on("signal", (data) => {
			socket.emit("answerCall", { signal: data, to: caller })
		})
		peer.on("stream", (stream) => {
			userVideo.current.srcObject = stream;
		})

		peer.signal(callerSignal)
		connectionRef.current = peer
	}

	const leaveCall = () => {
		setCallEnded(true)
		connectionRef.current.destroy()
	}


	return (
		<Box>
			<Grid container alignContent="center" direction="column">
				<Grid item>


					<Typography variant="h3">URSAC Online</Typography>
					<Box>
						<Paper>
							{stream && <video playsInline muted ref={myVideo} autoPlay style={{ width: "300px" }} />}
						</Paper>
						<Box>
							{callAccepted && !callEnded ?
								<video playsInline ref={userVideo} autoPlay style={{ width: "300px" }} /> :
								null}
						</Box>
					</Box>


				</Grid>
				<Grid item >
					<Grid container alignContent="center" direction="column">
						<Grid item>
							<TextField
								id="filled-basic"
								label="Name"
								variant="filled"
								value={name}
								onChange={(e) => setName(e.target.value)}
								style={{ marginBottom: "20px" }}
							/>
						</Grid>
						<Grid item>
							<CopyToClipboard text={me} style={{ marginBottom: "2rem" }}>
								<Button variant="contained" color="primary" fullWidth startIcon={<AssignmentIcon fontSize="large" />}>
									Copy ID
								</Button>
							</CopyToClipboard>
						</Grid>
						<Grid item>
							<TextField
								id="filled-basic"
								label="ID to call"
								variant="filled"
								value={idToCall}
								onChange={(e) => setIdToCall(e.target.value)}
							/>
						</Grid>
						<Grid item>
							<Box>
								{callAccepted && !callEnded ? (
									<Button variant="contained" color="secondary" fullWidth onClick={leaveCall}>
										End Call
									</Button>
								) : (
									<IconButton color="primary" aria-label="call" onClick={() => callUser(idToCall)}>
										<PhoneIcon fontSize="large" />
									</IconButton>
								)}
								{idToCall}
							</Box>
						</Grid>
					</Grid>

				</Grid>
			</Grid>

			<Container>




				<Box>
					{receivingCall && !callAccepted ? (
						<div className="caller">
							<Typography variant="h3" >{name} is calling...</Typography>
							<Button variant="contained" color="primary" onClick={answerCall}>
								Answer
							</Button>
						</div>
					) : null}
				</Box>
			</Container>
		</Box>
	)
}

export default VideoStream;
